            bool fs_ready = false;
            if (pulse >= 250 && pulse <= 550) { // Half 0
                if (fs_dec.pulse_in_bit == 1 && fs_dec.last_bit == 0) { fs_bit = 0; fs_ready = true; fs_dec.pulse_in_bit = 0; }
