void cc1101_send_it_v3(const char* data) {
    // IT V3: Sync (~9.3ms Low) + 32 bits
    // 0: T, 3T, T, 3T
    // 1: T, 3T, 3T, T
    // T = ~280us

    gpio_set_direction(GPIO_GDO0, GPIO_MODE_OUTPUT);
    gpio_isr_handler_remove(GPIO_GDO0);

    for (int r = 0; r < 5; r++) {
        cc1101_cmd_strobe(CC1101_STX);
        int retry = 100;
        while (retry-- > 0 && (cc1101_read_reg(0x35) & 0x1F) != 0x13) {
            ets_delay_us(10);
            if (retry == 50) cc1101_cmd_strobe(CC1101_STX);
        }

        gpio_set_level(GPIO_GDO0, 0);
        ets_delay_us(9300);

        for (int i = 0; i < 32; i++) {
            if (data[i] == '0') {
                gpio_set_level(GPIO_GDO0, 1); ets_delay_us(280);
                gpio_set_level(GPIO_GDO0, 0); ets_delay_us(840);
                gpio_set_level(GPIO_GDO0, 1); ets_delay_us(280);
                gpio_set_level(GPIO_GDO0, 0); ets_delay_us(840);
            } else {
                gpio_set_level(GPIO_GDO0, 1); ets_delay_us(280);
                gpio_set_level(GPIO_GDO0, 0); ets_delay_us(840);
                gpio_set_level(GPIO_GDO0, 1); ets_delay_us(840);
                gpio_set_level(GPIO_GDO0, 0); ets_delay_us(280);
            }
        }
        gpio_set_level(GPIO_GDO0, 1); ets_delay_us(280);
        gpio_set_level(GPIO_GDO0, 0); 

        cc1101_set_idle_mode();
        ets_delay_us(10000);
    }

    gpio_set_direction(GPIO_GDO0, GPIO_MODE_INPUT);
    gpio_isr_handler_add(GPIO_GDO0, gpio_isr_handler, NULL);
    cc1101_set_rx_mode();
}

void cc1101_send_hms(const char* hex_data) {
    // HMS: ~12-16 sync bits (0)
    // Bit 0: 400us High, 400us Low
    // Bit 1: 800us High, 400us Low

    gpio_set_direction(GPIO_GDO0, GPIO_MODE_OUTPUT);
    gpio_isr_handler_remove(GPIO_GDO0);

    cc1101_cmd_strobe(CC1101_STX);
    int retry = 100;
    while (retry-- > 0 && (cc1101_read_reg(0x35) & 0x1F) != 0x13) {
        ets_delay_us(10);
    }

    // Preamble (12 zeros)
    for(int i=0; i<12; i++) {
        gpio_set_level(GPIO_GDO0, 1); ets_delay_us(400);
        gpio_set_level(GPIO_GDO0, 0); ets_delay_us(400);
    }

    // Data bits (nibble wise, MSB first)
    int len = strlen(hex_data);
    for(int i=0; i<len; i++) {
        uint8_t n = 0;
        char c = hex_data[i];
        if (c >= '0' && c <= '9') n = c - '0';
        else if (c >= 'A' && c <= 'F') n = c - 'A' + 10;
        else if (c >= 'a' && c <= 'f') n = c - 'a' + 10;

        for(int b=3; b>=0; b--) {
            if ((n >> b) & 1) {
                gpio_set_level(GPIO_GDO0, 1); ets_delay_us(800);
                gpio_set_level(GPIO_GDO0, 0); ets_delay_us(400);
            } else {
                gpio_set_level(GPIO_GDO0, 1); ets_delay_us(400);
                gpio_set_level(GPIO_GDO0, 0); ets_delay_us(400);
            }
        }
    }

    gpio_set_level(GPIO_GDO0, 0);
    cc1101_set_idle_mode();
    gpio_set_direction(GPIO_GDO0, GPIO_MODE_INPUT);
    gpio_isr_handler_add(GPIO_GDO0, gpio_isr_handler, NULL);
    cc1101_set_rx_mode();
}

